import React from 'react';
import { namespace, circleNamespace } from '../constants';
import PropTypes from 'prop-types';

/** @typedef {import('../../index').IndeterminateProps} IndeterminateProps */

/** @type {React.FunctionComponent<IndeterminateProps>} */
const Indeterminate = ({ labelId, srLabel }) => (
  <div
    aria-label={srLabel}
    aria-labelledby={srLabel ? undefined : labelId}
    role="progressbar"
  >
    <svg
      className={`${namespace}__svg`}
      aria-hidden="true"
      viewBox="0 0 50 50"
      data-andes-progress-indicator-circular-icon
    >
      <circle
        className={circleNamespace}
        cx="50%"
        cy="50%"
        r="20"
        fill="none"
      />
    </svg>
  </div>
);

Indeterminate.propTypes = {
  labelId: PropTypes.string,
  srLabel: PropTypes.string,
};

export default Indeterminate;
