import React from 'react';
import PropTypes from 'prop-types';
import classNames from 'classnames';
import { VisuallyHidden } from '@andes/visually-hidden';
import useSrLabel from '@andes/common/build/hooks/useSrLabel';
import { useId } from '@andes/context';
import { namespace } from '../constants';
import Indeterminate from './Indeterminate';
import Determinate from './Determinate';
import { useThemeContext } from '@andes/themes';
import computeColorProps from '../utils/computeColorProps';

/**
 * @typedef {import('../..').DeterminateSpecificProps &
 * import('../../').ProgressIndicatorCircularProps
 * } ProgressIndicatorCircularPublicProps
 */

/**
 * @typedef {Object} ProgressIndicatorCircularInternalProps
 * @prop {string} [ariaLabelledBy]
 */

/**
 * @typedef {ProgressIndicatorCircularPublicProps &
 * ProgressIndicatorCircularInternalProps} ProgressIndicatorCircularProps
 */

/** @type {React.FunctionComponent<ProgressIndicatorCircularProps>} */
const ProgressIndicatorCircular = ({ ref, ...props }) => {
  const {
    id,
    size = 'medium',
    color = 'basic',
    type = 'indeterminate',
    className,
    label,
    value,
    children,
    continuous = false,
    srLabel,
    srAnnouncement,
    ariaLabelledBy,
    modifier,
  } = props;
  const componentId = useId(id);
  const { getThemedComponentClasses, themeHash } = useThemeContext();
  const labelId = ariaLabelledBy || (label && `${id}__label`);
  const srLabelVisibility = useSrLabel();

  const getSubcomponent = () => {
    const commonProps = { srLabel, labelId };

    if (type === 'determinate') {
      const determinateProps = { value, continuous, id: componentId, ...commonProps };
      return <Determinate {...determinateProps} />;
    }

    return <Indeterminate {...commonProps} />;
  };

  const computedColor = computeColorProps({ color });

  const progressIndicatorClassnames = classNames(namespace, className, {
    [`${namespace}--${type}`]: type,
    [`${namespace}--${size}`]: size,
    [`${namespace}--${computedColor}`]: computedColor,
    [`${namespace}--${modifier}`]: modifier,
  }, getThemedComponentClasses?.('progressIndicator'));

  return (
    <div
      ref={ref}
      className={progressIndicatorClassnames}
      data-andes-progress-indicator-circular
      data-andes-progress-indicator-circular-size={size}
      data-andes-progress-indicator-circular-type={type}
      {...themeHash}
    >
      <div className={`${namespace}__container`}>
        <div className={`${namespace}__progress`}>
          {srAnnouncement && (
            <VisuallyHidden role="status" aria-live="polite">
              {srLabelVisibility && srAnnouncement}
            </VisuallyHidden>
          )}
          {getSubcomponent()}
          {children && (
            <div className={`${namespace}__content`}>{children}</div>
          )}
        </div>
        {label && (
          <span className={`${namespace}__label`} id={labelId}>
            {label}
          </span>
        )}
      </div>
    </div>
  );
};

ProgressIndicatorCircular.displayName = 'ProgressIndicatorCircular';

ProgressIndicatorCircular.propTypes = {
  id: PropTypes.string,
  className: PropTypes.string,
  label: PropTypes.string,
  type: PropTypes.oneOf(['indeterminate', 'determinate']),
  size: PropTypes.oneOf(['xsmall', 'small', 'medium', 'large', 'xlarge']),
  color: PropTypes.oneOf(['blue', 'white', 'basic', 'inverse']),
  value: PropTypes.number,
  continuous: PropTypes.bool,
  children: PropTypes.node,
  ariaLabelledBy: PropTypes.string,
  srLabel: PropTypes.string,
  srAnnouncement: PropTypes.string,
  modifier: PropTypes.oneOf(['block', 'fullscreen', 'inline']),
};

export default ProgressIndicatorCircular;
