// Transforms any string to kebab case
/** @param {string} stringToConvert */
const transformToKebabCase = stringToConvert => stringToConvert
  // Separates camel case Words using -
  .replace(/([a-z])([A-Z])/g, '$1-$2')
  // Replaces spaces with -
  .replace(/[\s_]+/g, '-')
  .toLowerCase();

export default transformToKebabCase;
