import React from 'react';
import PropTypes from 'prop-types';
import classNames from 'classnames';
import { namespace, circleNamespace } from '../constants';

/** @typedef {import('../../index').DeterminateProps} DeterminateProps */

/** @type {React.FunctionComponent<DeterminateProps>} */
const Determinate = ({ continuous = false, id, labelId, srLabel, value = 0 }) => {
  const circunference = 124;
  const circlePercentage = (circunference * value) / 100;
  const circleClassnames = classNames(circleNamespace, {
    [`${circleNamespace}--continuous`]: continuous,
  });

  return (
    <div
      role="progressbar"
      aria-valuenow={value}
      aria-valuemin={0}
      aria-valuemax={100}
      aria-label={srLabel}
      aria-labelledby={srLabel ? undefined : labelId}
    >
      <svg
        className={`${namespace}__svg`}
        aria-hidden="true"
        viewBox="0 0 50 50"
        data-andes-progress-indicator-circular-icon
      >
        <circle
          className={`${circleNamespace}-bg`}
          cx="25"
          cy="25"
          r="20"
          fill="none"
        />
        <circle
          key={id}
          className={circleClassnames}
          strokeDasharray={circunference}
          strokeDashoffset={`${circunference - Math.min(circlePercentage, circunference)}`}
          cx="25"
          cy="25"
          r="20"
          fill="none"
        />
      </svg>
    </div>
  );
};

Determinate.propTypes = {
  continuous: PropTypes.bool,
  id: PropTypes.string,
  labelId: PropTypes.string,
  srLabel: PropTypes.string,
  value: PropTypes.number,
};

export default Determinate;
